import crypto = require('crypto');
import fs = require('fs');
import path = require('path');
import util = require('util');
import chalk = require('chalk');
import Parallel = require('async-parallel');
import Stopper from './Stopper';
import FailErrors from './FailErrors';
import {PromiseUtils} from './PromiseUtils';
import {SyncStage} from 'jibo-sync-stage';
import {utils} from 'jibo-sync-stage';

// Global flag for which method to generate update list (checksum vs timestamps)
export const USE_CHECKSUM = true;
export const CHECKSUMS_FILE = '.checksums';

const prify = PromiseUtils.promisify;
const stopper = new Stopper();

export interface FileDetails {
    timestamp: string;
    checksum: string;
    size: number;
}

export interface FileDetailsMap {
    [fileName: string]: FileDetails;
}

export interface Logger {
    debug(...args: any[]);
    log?(...args: any[]);
    info(...args: any[]);
    warn(...args: any[]);
    error(...args: any[]);
}

export default class Common {

    private static _verboseLog: boolean = false;
    private static _start: number = null;
    private static _logger: Logger = console;

    static getHostPort(url: string): {host: string, port: number} {
        // extract host and port from url; return as object if found; otherwise undefined is returned
        let strArray = url.split(':');
        if(strArray.length !== 2) {
            Common.info(chalk.red(`Url is not specified as [IP:port]: ${url}`));
            return undefined;
        }
        let host = strArray[0];
        // check we have a numerical port defined
        let port = Number(strArray[1]); // decimal conversion
        if(isNaN(port)) {
            Common.info(chalk.red(`Invalid port defined ${port}`));
            return undefined;
        }
        return {
            host: host,
            port: port,
        };
    }

    static setLogger(logger: Logger) {
        Common._logger = logger;
    }

    static setVerbose(enable?: boolean) {
        Common._verboseLog = !!enable;
    }

    static debug(...args:any[]) {
        if(Common._verboseLog) {
            if(Common._logger.debug) {
                Common._logger.debug.apply(Common._logger, args);
            }
            else if(Common._logger.log) {
                Common._logger.log.apply(Common._logger, args);
            }
        }
    }

    static info(...args:any[]) {
        Common._logger.info.apply(Common._logger, args);
    }

    static warn(...args:any[]) {
        Common._logger.warn.apply(Common._logger, args);
    }

    static error(...args:any[]) {
        Common._logger.error.apply(Common._logger, args);
    }

    static startTimer(str) {
        process.stdout.write(chalk.white(str) + ' ... ');
        Common._start = Date.now();
    }

    static endTimer() {
        Common.info(
            chalk.white('done.'),
            chalk.gray(utils.timeToString(Date.now() - Common._start))
        );
        Common._start = null;
    }

    static async getAllFileDetails(
        directory: string,
    ): Promise<FileDetailsMap> {
        if(!directory) {
            throw new Error(FailErrors.NO_DIRECTORY);
        }
        if(!await prify<boolean>(h => fs.exists(directory, h), false)) {
            return {};
        }

        const stats = await prify<fs.Stats>(h => fs.stat(directory, h));
        if(!stats.isDirectory()) {
            throw new Error(`Directory ${SyncStage.FOLDER} does not exist.`);
        }
        
        // get an array of the files within the directory
        const list: string[] =
            (await Common._findFilesRecursive(directory))
            .map(filePath => path.relative(directory, filePath));
        // now loop through the list to get our checksums
        const detailsList = {};
        await Parallel.each(list, async file => {
            if(stopper.doStop) {
                throw new Error(FailErrors.STOPPED);
            }
            const details: FileDetails =
                await Common._getFileDetails(path.join(directory, file));
            if(details) {
                // then actually store it in a consistent way:
                // representing directories in unix-style
                detailsList[file.replace(/\\/g, '/')] = details;
            }
        }, {concurrency: 5});
        return detailsList;
    }

    static async getTotalFileSize(files: string[]): Promise<number> {
        const sizes = stats => stats.map(stat => stat.size);
        const sum = numbers => numbers.reduce((a, b) => a + b, 0);
        const stats = await Parallel.map(
            files,
            file => prify(h => fs.stat(file, h)),
        );
        return sum(sizes(stats));
    }

    static async getTotalPathSize(path: string): Promise<number> {
        return Common.getTotalFileSize(await Common._findFilesRecursive(path));
    }

    // Asynchronously load file and get checksum hash value
    private static async _getFileDetails(filename): Promise<FileDetails> {
        if(!filename) {
            return null;
        }
        let stats: fs.Stats;
        try {
            stats = await prify<fs.Stats>(h =>
                fs.stat(path.normalize(filename), h));
        }
        catch(err) {
            Common.info(chalk.red(`Error getting checksum for ${filename}`, err));
            return null;
        }
        const fileDetails: FileDetails = {
            timestamp: null,
            checksum: null,
            size: stats ? stats.size : 0,
        };
        if(stats) {
            const date = stats.mtime;
            let time: number;
            if(util.isDate(date)) {
                // convert to 123.456 UNIX timestamp
                time = date.getTime() / 1000;
                // truncate it
                time = time < 0 ? Math.ceil(time) : Math.floor(time);
                fileDetails.timestamp = time.toString();
            }
            else {
                Common.info(chalk.red(`Error getting checksum for ${filename}: invalid stats.mtime`));
            }
        }
        else {
            Common.info(chalk.red(`Error getting checksum for ${filename}: no stats`));
        }
        if(USE_CHECKSUM) {
            try {
                const data = await prify<Buffer>(h =>
                    fs.readFile(path.normalize(filename), h));
                if(data) {
                    let cksum = crypto.createHash('md5');
                    cksum.update(data);
                    fileDetails.checksum = cksum.digest('hex');
                }
                else {
                    Common.info(chalk.red(`Error getting checksum for ${filename}: no data`));
                }
            }
            catch(err) {
                Common.info(chalk.red(`Error getting checksum for ${filename}`, err));
            }
        }
        return fileDetails;
    }

    private static async _existsAndDir(filePath: string): Promise<boolean> {
        try {
            const stat = await prify<fs.Stats>(h => fs.lstat(filePath, h));
            return stat.isDirectory();
        }
        catch(err) {
            Common.info(chalk.red(`Error getting file info on ${filePath}; skipping..`), err);
            return false;
        }
    }

    private static async _dirsOnly(filesAndDirs: string[]): Promise<string[]> {
        return await Parallel.filter(
            filesAndDirs,
            async filePath => await Common._existsAndDir(filePath),
            {concurrency: 5},
        );
    }

    private static async _existsAndFile(filePath: string): Promise<boolean> {
        try {
            // Ignore stale checksums file - we add a replacement to the end
            if(path.basename(filePath) === CHECKSUMS_FILE) {
                return false;
            }
            const stat = await prify<fs.Stats>(h => fs.lstat(filePath, h));
            return stat.isFile();
        }
        catch(err) {
            Common.info(chalk.red(`Error getting file info on ${filePath}; skipping..`), err);
            return false;
        }
    }

    private static async _filesOnly(filesAndDirs: string[]): Promise<string[]> {
        return await Parallel.filter(
            filesAndDirs,
            async filePath => await Common._existsAndFile(filePath),
            {concurrency: 5},
        );
    }

    private static async _findFilesRecursive(dir: string): Promise<string[]> {
        // Get all the files/directories in the current dir
    	const filesAndDirs: string[] =
            (await prify<string[]>(h => fs.readdir(dir, h)))
            .map(filePath => path.join(dir, filePath));
        if(stopper.doStop) {
            throw new Error(FailErrors.STOPPED);
        }
        // Get list of files only; this will be the return value
        const filesInDir: string[] = await Common._filesOnly(filesAndDirs);
        if(stopper.doStop) {
            throw new Error(FailErrors.STOPPED);
        }
        const subdirs: string[] = await Common._dirsOnly(filesAndDirs);
        if(stopper.doStop) {
            throw new Error(FailErrors.STOPPED);
        }
        // Loop recursively through the each subdirectory, adding results
        // of each subdir to the list of files to return to caller
        const filesInEachSubDir: string[][] =
            await Parallel.map(subdirs, async subdir => {
                if(stopper.doStop) {
                    throw new Error(FailErrors.STOPPED);
                }
                return await Common._findFilesRecursive(subdir);
            }, {concurrency: 5});
        if(stopper.doStop) {
            throw new Error(FailErrors.STOPPED);
        }
        // Concatenate files from this directory and each subdirectory
        return filesInEachSubDir.reduce(
            (files, subDirFiles) => files.concat(subDirFiles),
            filesInDir,
        );
    }
}
