const exec = require('child_process').exec;
import fs = require('fs');
import fsExtra = require('fs-extra');
import http = require('http');
import HttpStatus = require('http-status-codes');
import Meter = require('stream-meter');
import Parallel = require('async-parallel');
import path = require('path');
import tarFs = require('tar-fs');
import zlib = require('zlib');
import Common, {Logger, CHECKSUMS_FILE} from './Common';
import {PromiseUtils} from './PromiseUtils';

const URLUPLOAD = '/upload';
const URLDELETE = '/delete';
const URLCHECKSUM = '/checksum';
const URLCLOSE = '/close';
const URLPING = '/ping';
const URLTESTSIZE = '/testsize';

const prify = PromiseUtils.promisify;

export default class Server {

    static _server: http.Server;
    static _port: number;
    static _uploadDir = '.';
    static _setOwner = null;
    static _sizeLimit = 0;

    static async start(
        port: number,
        dest: string,
        setOwner: string,
        sizeLimit: number,
        verbose?: boolean,
        logger?: Logger,
    ): Promise<number> {
        if(logger) {
            Common.setLogger(logger);
        }
        Common.setVerbose(verbose);
        if(isNaN(port)) {
            throw new Error('\nInvalid port defined: ${Server._port}');
        }
        Server._uploadDir = dest;
        Server._setOwner = setOwner;
        Server._sizeLimit = sizeLimit;
        Common.setVerbose(verbose);
        if(logger) {
            Common.setLogger(logger);
        }
        // check if server is already running
        if(Server._server) {
            Common.info(`Sync server already listening on port ${Server._port}`);
            return Server._port;
        }
        else {
            Server._server = http.createServer(Server._handleRequest);
            // setting socket time out to 0 to disable (default was 2 mins)
            Server._server.timeout = 0;
            try {
                await prify(cb => Server._server.listen(port, '0.0.0.0', cb));
            }
            catch(err) {
                Server._port = null;
                Server._server = undefined;
                throw err;
            }
            Server._port = Server._server.address().port;
            return Server._port;
        }
    }

    static async stop(): Promise<string> {
        if(Server._server) {
            Server._server.close();
            Server._server = undefined;
            const port = Server._port;
            Server._port = null;
            return `Server closed on port ${port}`;
        }
        throw new Error('No server to close');
    }

    // function which handles requests and send response
    private static _handleRequest(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ): void {
        // only handling POST requests
        if(req.method !== 'POST') {
            return;
        }
        switch (req.url) {
            case URLUPLOAD: {
                Server._upload(req, res);
                break;
            }
            case URLDELETE: {
                Server._delete(req, res);
                break;
            }
            case URLCHECKSUM: {
                Server._getChecksum(req, res);
                break;
            }
            case URLCLOSE: {
                Server._closeServer(req, res);
                break;
            }
            case URLPING: {
                Server._pingServer(req, res);
                break;
            }
            case URLTESTSIZE: {
                Server._testSize(req, res);
                break;
            }
            default: {
                Server._sendStatus(res, HttpStatus.NOT_FOUND);
                break;
            }
        }
    }

    private static _readJSONBody<T>(req: http.IncomingMessage): Promise<T> {
        return new Promise<T>((resolve, reject) => {
            let body = '';
            req.on('data', (chunk) => {
                body += chunk;
            });
            req.on('end', () => {
                try {
                    resolve(JSON.parse(body));
                }
                catch(err) {
                    reject(err);
                }
            });
        });
    }

    private static _writeStatus(
        res: http.ServerResponse,
        httpStatus: number,
        contentType: string,
    ) {
        res.writeHead(
            httpStatus,
            HttpStatus.getStatusText(httpStatus),
            {'Content-Type': contentType},
        );
    }

    private static _sendStatus(
        res: http.ServerResponse,
        httpStatus: number,
    ): void {
        Server._writeStatus(res, httpStatus, 'text/plain');
        res.end();
    }

    private static _sendResponse(
        res: http.ServerResponse,
        httpStatus: number,
        obj: any,
    ): void {
        Server._writeStatus(res, httpStatus, 'application/json');
        res.write(JSON.stringify(obj));
        res.end();
    }

    private static async _getChecksum(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ): Promise<void> {
        let stringifiedChecksums: string;
        const checksumsFile = path.resolve(Server._uploadDir, CHECKSUMS_FILE);
        try {
            if(await prify(cb => fs.exists(checksumsFile, cb), false)) {
                stringifiedChecksums = await prify<string>(cb =>
                    fs.readFile(checksumsFile, 'utf-8', cb));
            }
        }
        catch(err) {
            Common.warn(`Problem reading ${CHECKSUMS_FILE}`, err);
        }
        if(!stringifiedChecksums) {
            try {
                const details =
                    await Common.getAllFileDetails(Server._uploadDir);
                stringifiedChecksums = JSON.stringify(details);
            }
            catch(err) {
                res.writeHead(500, {'Content-Type': 'application/json'});
                res.write(JSON.stringify(err.toString()));
                return res.end();
            }
        }
        res.writeHead(200, {
            'Content-Type': 'application/json',
            'Content-Length': stringifiedChecksums.length,
        });
        res.write(stringifiedChecksums);
        res.end();
    }

    private static async _setOwnership(
        directory: string,
        owner: string,
    ): Promise<void> {
        if(owner) {
            const parentDir: string = path.normalize(path.join(directory, '..'));
            const dirToSet: string =
                path.basename(parentDir).startsWith('@')
                    ? parentDir
                    : directory;
            try {
                await prify(cb =>
                    exec(`chown -R ${owner}:wheel ${dirToSet}`, cb));
                Common.info(`Ownership set to ${owner}:wheel`);
            }
            catch(err) {
                Common.info(`Error setting ownership to ${owner}:wheel`, err);
                throw err;
            }
        }
    }

    private static async _upload(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ): Promise<void> {
        Common.info('Receiving upload...');
        let startTime = Date.now();
        const checksumsFile = path.resolve(Server._uploadDir, CHECKSUMS_FILE);
        try {
            if(await prify(cb => fs.exists(checksumsFile, cb), false)) {
                await prify(cb => fsExtra.remove(checksumsFile, cb));
            }
        }
        catch(err) {
            Common.warn(`Problem deleting ${CHECKSUMS_FILE}`, err);
        }
        const {bytes, compressed} = await Server._untar(req, Server._uploadDir);
        await Server._setOwnership(Server._uploadDir, Server._setOwner);
        Common.info(`\ttook ${(Date.now() - startTime) / 1000} secs`);
        Common.info(`\t${bytes} bytes uploaded (${compressed} compressed)`);
        res.writeHead(204, "OK", {'Content-Type': 'text/plain'});
        res.end();
    }

    private static async _untar(
        stream: http.IncomingMessage,
        directory: string,
    ): Promise<{bytes: number, compressed: number}> {
        await prify(cb => fsExtra.ensureDir(directory, cb));
        let sizeMeter = new Meter();
        let compressedMeter = new Meter();
        // all dirs and files should be readable
        let extractOpts = {dmode: 0o750, fmode: 0o640};
        try {
            await prify(cb => stream.pipe(compressedMeter)
                .pipe(zlib.createGunzip())
                .pipe(sizeMeter)
                .pipe(tarFs.extract(directory, extractOpts))
                .on('finish', cb)
                .on('error', err => {
                    Common.info('problem with POST stream', err);
                    throw err;
                }));
        }
        catch(err) {
            Common.info('Problem extracting tar stream', err);
            throw err;
        }
        return {bytes: sizeMeter.bytes, compressed: compressedMeter.bytes};
    }

    private static async _delete(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ): Promise<void> {
        Common.info('Receiving delete request...');
        let startTime = Date.now();
        let data: {deleteList: string[]};
        try {
            data = await Server._readJSONBody<{deleteList: string[]}>(req);
        }
        catch(error) {
            return Server._sendResponse(
                res,
                HttpStatus.BAD_REQUEST,
                'Invalid delete request. Request body is not valid JSON',
            );
        }
        const checksumsFile =
            path.resolve(Server._uploadDir, CHECKSUMS_FILE);
        try {
            if(await prify(cb => fs.exists(checksumsFile, cb), false)) {
                await prify(cb => fsExtra.remove(checksumsFile, cb));
            }
        }
        catch(err) {
            Common.warn(`Problem deleting ${CHECKSUMS_FILE}`, err);
        }
        try {
            await Parallel.each<string, void>(data.deleteList, async file => {
                const filePath = path.resolve(Server._uploadDir, file);
                await prify(cb => fsExtra.remove(filePath, cb));
            }, {concurrency: 5});
        }
        catch(err) {
            Common.info('Error executing deletes', err);
            return Server._sendStatus(res, HttpStatus.INTERNAL_SERVER_ERROR);
        }
        Server._sendStatus(res, HttpStatus.OK);
        Common.info('\ttook ' + (Date.now() - startTime)/1000 + ' secs');
    }

    private static async _closeServer(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ) {
        try {
            const msg = await Server.stop();
            Common.info(msg);
            Server._sendResponse(res, HttpStatus.OK, msg);
        }
        catch(err) {
            Common.info(err);
            Server._sendResponse(res, HttpStatus.INTERNAL_SERVER_ERROR, err);
        }
    }

    private static _pingServer(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ) {
        Server._sendStatus(res, HttpStatus.NO_CONTENT);
    }

    private static async _testSize(
        req: http.IncomingMessage,
        res: http.ServerResponse,
    ): Promise<void> {
        if(Server._sizeLimit === 0) {
            Server._sendStatus(res, HttpStatus.OK);
            return;
        }
        let body: {size: number};
        try {
            body = await Server._readJSONBody<{size: number}>(req);
        }
        catch(err) {
            console.error(err);
            Server._sendResponse(res, HttpStatus.BAD_REQUEST, {
                Status: 'ERROR',
                Message: 'Invalid testsize request. Request body is not valid JSON',
            });
        }
        const clientDirSize = body.size;
        console.log(`source directory size ${clientDirSize}`);
        try {
            const parentDirSize = await Common.getTotalPathSize(path.join(Server._uploadDir, '..'));
            console.log(`total directory size ${parentDirSize}`);
            const targetDirSize = await Common.getTotalPathSize(Server._uploadDir);
            console.log('target directory size', targetDirSize);
            const notTargetDirSize = parentDirSize - targetDirSize;
            console.log('outside target dir size', notTargetDirSize);
            const totalSizeIfSynced = notTargetDirSize + clientDirSize;
            console.log('total directory size if synced', totalSizeIfSynced);
            console.log('size limit', Server._sizeLimit);
            Server._sendStatus(res,
                totalSizeIfSynced <= Server._sizeLimit
                    ? HttpStatus.OK
                    : HttpStatus.INSUFFICIENT_STORAGE);
        }
        catch(err) {
            console.error(err);
            Server._sendStatus(res, HttpStatus.INTERNAL_SERVER_ERROR);
        }
    }
}
