import {EventEmitter} from 'events';

export default class Stopper extends EventEmitter {

    private _doStop: boolean = false;

    stop() {
        this._doStop = true;
        this.emit('stop');
    }

    get doStop() {
        return this._doStop;
    }

    reset() {
        this.removeAllListeners();
        this._doStop = false;
    }
}
